// runOnceForAllItems. Webhook GET -> query params bajo $json.query.
const src = $input.first().json;
const q = src.query || src.body || src;
const org = (q.org || '').toString().trim();
const from = (q.from || '').toString().trim();
const to = (q.to || '').toString().trim();
const fail = (error, detail) => [{ json: { ok:false, http_status:400, error, detail: detail||null, org, from, to } }];

if (!org || !from || !to) return fail('missing_params','org, from y to son obligatorios');
const RE = /^\d{4}-\d{2}-\d{2}$/;
if (!RE.test(from) || !RE.test(to)) return fail('bad_date_format','from/to deben ser YYYY-MM-DD');

// createdAtUnix es epoch seconds UTC en Mongo. from = inicio de dia, to = fin de dia inclusivo.
const fromMs = Date.parse(from + 'T00:00:00Z');
const toMs   = Date.parse(to   + 'T23:59:59Z');
if (Number.isNaN(fromMs) || Number.isNaN(toMs)) return fail('bad_date_value','fecha invalida');
if (fromMs > toMs) return fail('range_inverted','from debe ser <= to');
const days = (toMs - fromMs) / 86400000;
if (days > 93) return fail('range_too_wide','el rango no puede exceder 93 dias');

const fromUnix = Math.floor(fromMs / 1000);
const toUnix   = Math.floor(toMs / 1000);
return [{ json: { ok:true, org, from, to, fromUnix, toUnix, startedAt: Date.now(), generated_at: new Date().toISOString() } }];

// runOnceForAllItems. Entrada = N docs Mongo (1 por item).
const docs = $input.all().map(i => i.json).filter(d => d && (d.ticketId != null));
const meta = $('Validate Query').first().json; // org/from/to/fromUnix/toUnix/startedAt/generated_at
const CHUNK = 100; // show_many cap de Zendesk

if (docs.length === 0) {
  // 0 tickets: emitir 1 item para que el flujo llegue a Assemble y produzca _meta count:0.
  return [{ json: { ids:'', batchIndex:0, empty:true } }];
}
const ids = docs.map(d => String(d.ticketId));
const batches = [];
for (let i = 0; i < ids.length; i += CHUNK) batches.push(ids.slice(i, i + CHUNK));
return batches.map((b, idx) => ({
  json: { ids: b.join(','), batchIndex: idx, empty:false, ticketCount: ids.length },
  pairedItem: { item: 0 }
}));

// runOnceForAllItems. Entrada = M responses show_many (item.json = {tickets:[],users:[],groups:[],organizations:[]}).
const MAX_TICKETS = 800; // cap defensivo: ~800 comments secuenciales caben en 300s con margen. 284 (test) pasa holgado.
const RUT_FIELD_KEYS = ['rut','RUT','rut_cliente','tax_id','identificador_fiscal','external_id'];

const usersById = {}, groupsById = {}, orgsById = {}, ticketEnrich = {};
let enrichOk = 0, enrichErr = 0;

for (const it of $input.all()) {
  const r = it.json || {};
  // item vacio / error de show_many (onError=continueRegularOutput)
  if (r.error || (!r.tickets && !r.users && !r.organizations)) { enrichErr++; continue; }
  enrichOk++;
  for (const u of (r.users || []))   usersById[String(u.id)]  = { name: u.name || null, role: u.role || null };
  for (const g of (r.groups || []))  groupsById[String(g.id)] = g.name || null;
  for (const o of (r.organizations || [])) {
    let rut = null;
    const of_ = o.organization_fields || {};
    for (const k of RUT_FIELD_KEYS) { if (k === 'external_id') { if (o.external_id) { rut = o.external_id; break; } } else if (of_[k]) { rut = of_[k]; break; } }
    orgsById[String(o.id)] = { name: o.name || null, rut: rut || null };
  }
  for (const t of (r.tickets || [])) {
    ticketEnrich[String(t.id)] = {
      tags: Array.isArray(t.tags) ? t.tags : [],
      description: (t.description || '').slice(0, 4000)
    };
  }
}

// Orden canonico de tickets = orden de Mongo (createdAtUnix asc en el find).
const mongoDocs = $('Mongo Find Tickets').all().map(i => i.json).filter(d => d && d.ticketId != null);
let ids = mongoDocs.map(d => String(d.ticketId));
let capped = false;
if (ids.length > MAX_TICKETS) { ids = ids.slice(0, MAX_TICKETS); capped = true; }

// _maps SOLO en el primer item (Assemble lo lee con .first()). Duplicarlo en N items
// causaba OOM del sandbox para orgs grandes (~700+ tickets, ej. Sodexo) -> 'Unknown error'.
const maps = { usersById, groupsById, orgsById, ticketEnrich, enrichOk, enrichErr, capped, capLimit: MAX_TICKETS };
if (ids.length === 0) {
  // 0 tickets en rango: 1 item marca para que Assemble emita _meta count:0 (no llama comments con ticketId valido).
  return [{ json: { ticketId: null, empty:true, _maps: maps }, pairedItem: { item: 0 } }];
}
return ids.map((id, idx) => ({ json: idx === 0 ? { ticketId: id, _maps: maps } : { ticketId: id }, pairedItem: { item: idx } }));

// runOnceForAllItems. Entrada = N responses de comments (item.json = {comments:[],users:[]} de /tickets/{id}/comments.json?include=users).
const t0 = $('Validate Query').first().json;
const maps = ($('Build Comment Tasks').first().json || {})._maps || {};
const usersById = maps.usersById || {}, groupsById = maps.groupsById || {}, orgsById = maps.orgsById || {}, ticketEnrich = maps.ticketEnrich || {};

// Mongo docs por ticketId (fuente de metricas + IDs).
const byId = {};
for (const i of $('Mongo Find Tickets').all()) { const d = i.json; if (d && d.ticketId != null) byId[String(d.ticketId)] = d; }

// Comments por ticketId. El nodo Comments emite 1 response por item de entrada (Build Comment Tasks),
// preservando pairedItem -> permite resolver el ticketId exacto. Fallback: indice posicional.
const tasks = $('Build Comment Tasks').all();
const commentItems = $input.all();
const commentsByTicket = {};
let commentErrCount = 0;
for (let k = 0; k < commentItems.length; k++) {
  const item = commentItems[k];
  const resp = item.json || {};
  let tid = null;
  const pi = item.pairedItem;
  let srcIdx = null;
  if (pi != null) srcIdx = Array.isArray(pi) ? (pi[0] && pi[0].item) : (typeof pi === 'object' ? pi.item : (typeof pi === 'number' ? pi : null));
  if (srcIdx != null && tasks[srcIdx] && tasks[srcIdx].json) tid = tasks[srcIdx].json.ticketId;
  if (tid == null && tasks[k] && tasks[k].json) tid = tasks[k].json.ticketId; // fallback posicional
  if (tid == null && resp.comments && resp.comments[0]) tid = resp.comments[0].ticket_id; // fallback Zendesk
  if (tid == null) { continue; }
  if (resp.error || (!resp.comments && !resp.users)) commentErrCount++;
  // users[] del propio response resuelve autores agentes Y clientes/end-users.
  const localUsers = {};
  for (const u of (resp.users || [])) localUsers[String(u.id)] = { name: u.name || null, role: u.role || null };
  const arr = (resp.comments || []).map(c => {
    const aid = c.author_id != null ? String(c.author_id) : null;
    const a = (aid && (localUsers[aid] || usersById[aid])) || {};
    return { id: c.id, author: { id: c.author_id != null ? c.author_id : null, name: a.name || null, role: a.role || null },
             created_at: c.created_at || null, body: c.body || '', public: !!c.public };
  });
  commentsByTicket[String(tid)] = arr;
}

// Lineas en el orden de Mongo (1 por ticket; dedup defensivo).
const seen = new Set();
const orderedIds = $('Mongo Find Tickets').all().map(i => String(i.json.ticketId)).filter(v => { if (seen.has(v)) return false; seen.add(v); return true; });
const lines = [];
const errors = [];
if (maps.enrichErr) errors.push('show_many_batches_failed:' + maps.enrichErr);
if (maps.capped) errors.push('ticket_cap_applied:' + maps.capLimit);
if (commentErrCount) errors.push('comments_failed_partial:' + commentErrCount);

for (const id of orderedIds) {
  const d = byId[id]; if (!d) continue;
  const enr = ticketEnrich[id] || { tags:[], description:'' };
  const org = orgsById[String(d.organizationId)] || { name:null, rut:null };
  const agent = { id: d.assigneeId || null, name: d.assigneeId ? ((usersById[String(d.assigneeId)] || {}).name || null) : null };
  const group = { id: d.groupId || null, name: d.groupId ? (groupsById[String(d.groupId)] || null) : null };
  // description: preferir show_many; fallback al body del primer comment publico.
  let description = enr.description || null;
  if (!description) { const fc = (commentsByTicket[id] || []).find(c => c.public); description = fc ? String(fc.body || '').slice(0, 4000) : null; }
  lines.push({
    id: d.ticketId,
    subject: d.subject != null ? d.subject : null,
    status: d.status != null ? d.status : null,
    priority: d.priority != null ? d.priority : null,
    type: d.type != null ? d.type : null,
    created_at: d.createdAt != null ? d.createdAt : null,
    updated_at: d.updatedAt != null ? d.updatedAt : null,
    solved_at: d.solvedAt != null ? d.solvedAt : null,
    frt_min: d.frtMin != null ? d.frtMin : null,
    reopens: d.reopens != null ? d.reopens : null,
    sla_breached: d.slaBreached != null ? d.slaBreached : null,
    csat: d.csat != null ? d.csat : null,
    agent, group,
    organization: { id: d.organizationId || null, name: org.name, rut: org.rut },
    category: d.categoria != null ? d.categoria : null,
    product: d.producto != null ? d.producto : null,
    subproduct: d.subproducto != null ? d.subproducto : null,
    linea_negocio: d.lineaNegocio != null ? d.lineaNegocio : null,
    via_channel: d.viaChannel != null ? d.viaChannel : null,
    canal_normalizado: d.canalNormalizado != null ? d.canalNormalizado : null,
    escalamientos: { paso_sn1: d.pasoSn1 != null ? d.pasoSn1 : null, esc_sn2: d.escSn2 != null ? d.escSn2 : null, esc_mo: d.escMo != null ? d.escMo : null, devol: d.devol != null ? d.devol : null },
    description,
    tags: enr.tags,
    comments: commentsByTicket[id] || []
  });
}

const meta = { _meta: true, org: t0.org, from: t0.from, to: t0.to, count: lines.length,
  generated_at: new Date().toISOString(), elapsed_ms: Date.now() - (t0.startedAt || Date.now()),
  errors, schema_version: 2 };

const ndjson = [JSON.stringify(meta)].concat(lines.map(l => JSON.stringify(l))).join('\n') + '\n';
const b64 = Buffer.from(ndjson, 'utf8').toString('base64');
const fname = `cs-export-${t0.org}-${t0.from}_${t0.to}.jsonl`;
return [{
  json: { ok:true, count: lines.length, filename: fname, errors: errors.length },
  binary: { data: { data: b64, mimeType: 'application/x-ndjson', fileName: fname, fileExtension: 'jsonl' } }
}];

// runOnceForAllItems. Rama FALSE del IF (validacion 400). Materializa el error como JSONL binary de 1 linea
// para no romper el front (que hace r.blob() incondicional, no parsea JSON).
const e = $input.first().json || {};
const meta = { _meta: true, ok: false, http_status: e.http_status || 400, error: e.error || 'bad_request',
  detail: e.detail || null, org: e.org || null, from: e.from || null, to: e.to || null,
  generated_at: new Date().toISOString(), schema_version: 2 };
const body = JSON.stringify(meta) + '\n';
const org = e.org || 'NA', from = e.from || 'NA', to = e.to || 'NA';
const b64 = Buffer.from(body, 'utf8').toString('base64');
return [{
  json: { ok:false, error: meta.error },
  binary: { data: { data: b64, mimeType: 'application/x-ndjson', fileName: `cs-export-${org}-${from}_${to}.jsonl`, fileExtension: 'jsonl' } }
}];
